// Agrega esto al principio del bucle for en tu nodo Code
const messageType = $('Webhook').first().json.body.conversation.messages[0].message_type;

if (messageType !== 0) {
  return []; // Si no es un mensaje de cliente, detén este ítem aquí.
}
for (let item of $input.all()) {
  // Extraemos los datos originales del Webhook
  const webhookData = $('Webhook').first().json.body.conversation;
  const messageData = webhookData.messages[0];
  const sender = messageData.sender;

  // Limpiamos y formateamos el móvil al formato 0xxx-xxxxxxx
  let rawPhone = sender.phone_number ? sender.phone_number.toString() : sender.identifier;
  let movilFormateado = rawPhone.replace(/\D/g, '').slice(-10).replace(/(\d{3})(\d{7})/, '$1-$2');

  // Convertimos el timestamp a fecha local de Venezuela
 // Convertimos el timestamp a un formato ISO que n8n entiende perfectamente
let fechaLocal = new Date(webhookData.timestamp * 1000).toISOString();

  // Estructuramos la salida
  item.json = {
    message: messageData.content,
    sessionId: sender.identifier.replace(/\D/g, ''),
    name_whatsapp: sender.name, // Guardamos el nombre de WA por si es nuevo
    movil: movilFormateado,
    remoteJid: sender.identifier,
    date_time: fechaLocal
  };
}
return $input.all();
